previewCss:
.darma-loader-uiverse-flip-letter-marquee {
  perspective: 700px;
  background: var(--loader-color, #ef4444);
  padding: 12px 22px;
  border-radius: 10px;
  display: inline-flex;
  gap: 1px;
}
.darma-loader-uiverse-flip-letter-marquee > span {
  font-size: 42px;
  line-height: 1;
  font-family: "Franklin Gothic Medium", Arial, sans-serif;
  display: inline-block;
  animation: darma-loader-uiverse-flip-letter-marquee-letterFlip 2.6s infinite linear;
  transform-origin: 0 70%;
  transform-style: preserve-3d;
  color: #111111;
}
.darma-loader-uiverse-flip-letter-marquee > span:nth-child(even) { color: var(--loader-secondary-color, #ffffff); }
.darma-loader-uiverse-flip-letter-marquee > span:nth-child(2) { animation-delay: .3s; }
.darma-loader-uiverse-flip-letter-marquee > span:nth-child(3) { animation-delay: .6s; }
.darma-loader-uiverse-flip-letter-marquee > span:nth-child(4) { animation-delay: .9s; }
.darma-loader-uiverse-flip-letter-marquee > span:nth-child(5) { animation-delay: 1.2s; }
.darma-loader-uiverse-flip-letter-marquee > span:nth-child(6) { animation-delay: 1.5s; }
.darma-loader-uiverse-flip-letter-marquee > span:nth-child(7) { animation-delay: 1.8s; }
@keyframes darma-loader-uiverse-flip-letter-marquee-letterFlip { 35%,100% { transform: rotateZ(360deg); } }

